'use strict';
/* header-menu */

$(document).on('click', '.header-menu a', function () {
  var li = $(this).parent();
  var to = $(this).attr('href') || $(this).data('href');

  if (li.hasClass('menu-item-has-children')) {
    if (!$('html').hasClass('header-menu-opened')) {
      li.children('.header-submenu').toggleClass('active');
      li.toggleClass('active');
    }
  } else {
    scrollToBlock(to, 1000, 70);
    closeHeaderMenu();
    $('.header-menu li, .header-submenu').removeClass('active');
  }

  return false;
});
$(document).on('click', function (event) {
  if ($(event.target).closest('.menu-item-has-children').length) return;
  $('.menu-item-has-children, .header-submenu').removeClass('active');
});
$(document).on('click', '.header-menu-open', function (event) {
  $('html').addClass('header-menu-opened header-menu-is-open');
  return false;
});
$(document).on('click', '.header-menu-close', function (event) {
  closeHeaderMenu();
  return false;
});
$(document).on('click', function (event) {
  if (event.isTrigger) return;
  if ($(event.target).closest('.header-menu-open, .header-menu-body').length) return;
  if (!$('html').hasClass('header-menu-opened')) return;
  closeHeaderMenu();
});

function closeHeaderMenu() {
  $('html').removeClass('header-menu-is-open');
  setTimeout(function () {
    $('html').removeClass('header-menu-opened');
  }, 400);
}

$(document).on('click', '.header-menu-is-open .header-menu .menu-item-has-children>a', function (event) {
  var li = $(this).closest('li');

  if (li.hasClass('active')) {
    closeMenu();
  } else {
    closeMenu();
    li.addClass('active');
    li.children('.header-submenu').slideDown(400);
  }

  function closeMenu() {
    li.parent().children('.menu-item-has-children').removeClass('active');
    li.parent().children('.menu-item-has-children').children('.header-submenu').slideUp(400);
  }

  return false;
});
/* scroll */

function scrollToBlock(to, speed, offset) {
  if (typeof to === 'string') to = $(to);
  if (!to[0]) return;
  offset = offset || 0;
  speed = speed || 1000;
  $('html, body').stop().animate({
    scrollTop: to.offset().top - offset
  }, speed);
}

$('.scroll-to-btn').on('click', function () {
  var to = $(this).attr('href') || $(this).data('href');
  scrollToBlock(to);
  return false;
});
/* header-fixed */

$(window).on('load scroll resize', function () {
  if ($(this).scrollTop() > 0) {
    $('.header').addClass('fixed');
  } else {
    $('.header').removeClass('fixed');
  }
});
/* fancybox */

$('[data-fancybox]').fancybox({
  hash: false,
  buttons: ['thumbs', 'close'],
  loop: true,
  parentEl: 'html',
  onUpdate: function onUpdate(instance, current) {
    if (current.type !== 'iframe') return;
    set16x9(current);
  }
});
/* tabs */

$(document).on('click', '.tabs-nav a', function (event) {
  event.preventDefault();
  var t = $(this),
      li = t.parent(),
      tab = t.attr('href'),
      tabs = t.closest('.tabs-nav').data('tabs');
  if (li.hasClass('active')) return;
  t.closest('.tabs-nav').find('li').removeClass('active');
  $(tabs).children('.tab-block').removeClass('active');
  li.addClass('active');
  $(tab).addClass('active');
});
/* checkbox */

$('.checkbox:checked').closest('label').addClass('active');
$(document).on('change', '.checkbox', function () {
  var t = $(this);

  if (t.prop('checked')) {
    t.closest('label').addClass('active');
  } else {
    t.closest('label').removeClass('active');
  }
});
/* radio */

$('.radio:checked').closest('label').addClass('active');
$(document).on('change', '.radio', function () {
  var t = $(this),
      name = t.attr('name');
  $('[name="' + name + '"]').closest('label').removeClass('active');

  if (t.prop('checked')) {
    t.closest('label').addClass('active');
  } else {
    t.closest('label').removeClass('active');
  }
});
/* faq */

$(document).on('click', '.faq-link', function () {
  var t = $(this);

  if (t.hasClass('active')) {
    close();
  } else {
    close();
    t.addClass('active');
    t.closest('.faq-block').find('.faq-content').slideDown(400);
  }

  function close() {
    $('.faq-link').removeClass('active');
    $('.faq-content').slideUp(400);
  }

  return false;
});
/* modals */

var isOpenModal = false;
$(document).on('click', '.modal-open-btn', function () {
  var t = $(this),
      modal = t.data('modal') || t.attr('href'),
      title = t.data('title');

  if (title) {
    $(modal).find('[name="title"]').val(title);
  }

  openModal(modal);
  return false;
});
$(document).on('click', '.modal-close-btn, .modal-close-link', function () {
  $.fancybox.close(true);
  return false;
});

function openModal(modal, callback) {
  var timeout = 0;
  if ($('html').hasClass('fancybox-is-open')) isOpenModal = true;
  if (isOpenModal) timeout = 350;
  $.fancybox.close(true);
  setTimeout(function () {
    $.fancybox.open({
      src: modal,
      type: 'inline',
      opts: getFancyboxModalOpts(modal, callback)
    });
    setTimeout(function () {
      isOpenModal = false;
    }, 400);
  }, timeout);
}

function getScrollbarWidth() {
  var outer = document.createElement('div');
  outer.style.visibility = 'hidden';
  outer.style.width = '100px';
  document.body.appendChild(outer);
  var widthNoScroll = outer.offsetWidth;
  outer.style.overflow = 'scroll';
  var inner = document.createElement('div');
  inner.style.width = '100%';
  outer.appendChild(inner);
  var widthWithScroll = inner.offsetWidth;
  outer.parentNode.removeChild(outer);

  if ($('html').height() <= $(window).height()) {
    return 0;
  }

  return widthNoScroll - widthWithScroll;
}

function getFancyboxModalOpts(modal, callback) {
  var scrollbarWidth = getScrollbarWidth();
  return {
    smallBtn: false,
    toolbar: false,
    touch: false,
    animationDuration: 400,
    beforeLoad: function beforeLoad() {
      $('html').addClass('fancybox-is-open').css({
        marginRight: scrollbarWidth
      });
      $('.header').css({
        right: scrollbarWidth
      });
    },
    afterLoad: function afterLoad() {
      setTimeout(function () {
        $(modal).addClass('active');
      }, 0);
      if (callback) callback();
    },
    beforeClose: function beforeClose() {
      $(modal).addClass('close');
      setTimeout(function () {
        $(modal).removeClass('active close');
      }, 400);
    },
    afterClose: function afterClose() {
      isOpenResults = false;
      if (isOpenModal) return;
      $('html').removeClass('fancybox-is-open').css({
        marginRight: 0
      });
      $('.header').css({
        right: 0
      });
    },
    onUpdate: function onUpdate(instance, current) {
      if (current.src == '#modal-map') {
        set16x9(current);
      }
    }
  };
}
/* select-number */


;

(function () {
  $(document).on('click', '.select-number-btn', function (event) {
    event.preventDefault();
    var t = $(this),
        input = t.closest('.select-number').find('.select-number-input'),
        val = +input.val(),
        min = +input.attr('min') || 0,
        max = +input.attr('max') || Infinity,
        step = input.data('step') || 1;

    if (t.hasClass('select-number-btn-minus')) {
      if (val == min) return;
      input.val(val - step);
    } else {
      if (val == max) return;
      input.val(val + step);
    }
  });
  var value;
  $(document).on('focus', '.select-number-input', function () {
    value = $(this).val();
    $(this).val('');
  });
  $(document).on('blur', '.select-number-input', function () {
    var t = $(this),
        val = +t.val(),
        min = +t.attr('min') || 0,
        max = +t.attr('max') || Infinity;

    if (!val) {
      t.val(value);
      return;
    }

    if (val < min) {
      t.val(min);
    }

    if (val > max) {
      t.val(max);
    }
  });
  $(document).on('keypress', '.select-number-input', function (event) {
    var key, keyChar;
    if (event.keyCode) key = event.keyCode;else if (event.which) key = event.which;
    if (key == null || key == 0 || key == 8 || key == 13 || key == 9 || key == 39) return true;
    keyChar = String.fromCharCode(key);
    if (!/[0-9]/.test(keyChar)) return false;
  });
})();
/* form */


$('[type="tel"]').on('keypress', function (event) {
  var key, keyChar;
  if (event.keyCode) key = event.keyCode;else if (event.which) key = event.which;
  if (key == null || key == 0 || key == 8 || key == 13 || key == 9 || key == 39 || key == 48) return true;
  keyChar = String.fromCharCode(key);
  if (!/[1-9]/.test(keyChar)) return false;
});
$('.form').on('submit', function () {
  var t = $(this);
  t.find('.submit').attr('disabled', true);
  t.attr('action', '__send__.php');
  t.ajaxSubmit({
    clearForm: true,
    success: function success(answer) {
      console.log(answer);
      t.find('.submit').removeAttr('disabled');
      t.attr('action', '?');

      if (answer == 'error') {
        alert('Что-то пошло не так... Пожалуйста, свяжитесь с нами по телефону.');
        return;
      }

      t.find('.checkbox-label, .radio-label').removeClass('active');
      t.find('.select-number-input').val(t.find('.select-number-input').data('value'));

      if (t.hasClass('pricelist-form')) {
        $('.pricelist-link')[0].click();
        $.fancybox.close(true);
      } else {
        openModal('#modal-sent');
      }
    }
  });
  return false;
});
