/* test */


var isTestOpen = false;
var testScroll = false;
var testTime = false;
setTimeout(function () {
  if (isTestOpen) return;
  testTime = true;

  if (testTime && testScroll) {
    isTestOpen = true;
    openModal('#modal-test');
  }
}, 40000);
$(window).on('load scroll resize', function () {
  if (isTestOpen) return;
  var point = $('#docs').offset().top + $('#docs').innerHeight() - 80;

  if ($(this).scrollTop() > point) {
    testScroll = true;

    if (testTime && testScroll) {
      isTestOpen = true;
      openModal('#modal-test');
    }
  }
});
$(document).on('click', '.test-start-btn', function () {
  $('.test-start, .test-steps').toggleClass('active');
  return false;
});
$(document).on('change', '.test-step-radio', function () {
  $(this).closest('.test-step').find('.test-step-next-btn').removeAttr('disabled');
});
$(document).on('change', '.test-step-checkbox', function () {
  var step = $(this).closest('.test-step');
  var isChecked = false;
  step.find('.test-step-checkbox').each(function () {
    if ($(this).prop('checked')) {
      isChecked = true;
      return false;
    }
  });

  if (isChecked) {
    step.find('.test-step-next-btn').removeAttr('disabled');
  } else {
    step.find('.test-step-next-btn').attr('disabled', true);
  }
});
$(document).on('click', '.test-step-next-btn', function () {
  var step = $('.test-step.active');
  var stepNext = step.next();
  stepNext.addClass('next');
  step.addClass('prev');

  if (stepNext.hasClass('test-step-finish')) {
    $('.test-steps-title').addClass('hidden');
  }

  setTimeout(function () {
    stepNext.addClass('active');
  }, 100);
  setTimeout(function () {
    step.removeClass('prev active');
  }, 400);
  setTimeout(function () {
    stepNext.removeClass('next');
  }, 500);
  return false;
});

document.addEventListener("DOMContentLoaded", function() { var lazyBackgrounds = [].slice.call(document.querySelectorAll(".lazy-bg")); if ("IntersectionObserver" in window) { let lazyBackgroundObserver = new IntersectionObserver(function(entries, observer) { entries.forEach(function(entry) { if (entry.isIntersecting) { entry.target.classList.remove("lazy-bg"); lazyBackgroundObserver.unobserve(entry.target); } }); }); lazyBackgrounds.forEach(function(lazyBackground) { lazyBackgroundObserver.observe(lazyBackground); }); } });

document.addEventListener("DOMContentLoaded", function() {
    var mapBlock = document.getElementById('map-lazy-load');
    if (mapBlock) {
        var mapLoaded = false;
        var startMap = function() {
            if (mapLoaded) return;
            mapLoaded = true;
            window.removeEventListener('mousemove', startMap);
            window.removeEventListener('touchstart', startMap);
            window.removeEventListener('scroll', startMap);
            var code = mapBlock.getAttribute('data-map-code');
            if (code) {
                var container = document.createElement('div');
                container.innerHTML = code;
                var childNodes = Array.prototype.slice.call(container.childNodes);
                for (var i = 0; i < childNodes.length; i++) {
                    var node = childNodes[i];
                    if (node.tagName === 'SCRIPT') {
                        var script = document.createElement('script');
                        if (node.src) script.src = node.src;
                        if (node.innerHTML) script.innerHTML = node.innerHTML;
                        document.body.appendChild(script);
                    } else {
                        mapBlock.appendChild(node);
                    }
                }
            }
        };
        window.addEventListener('mousemove', startMap, {passive: true});
        window.addEventListener('touchstart', startMap, {passive: true});
        if ('IntersectionObserver' in window) {
            var observer = new IntersectionObserver(function(entries) {
                if (entries[0].isIntersecting) {
                    startMap();
                    observer.unobserve(mapBlock);
                }
            });
            observer.observe(mapBlock);
        }
    }
});